<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ubuntu Web Desktop</title>
    <style>
        :root {
            --ubuntu-orange: #E95420;
            --ubuntu-dark: #300a24;
            --ubuntu-panel: rgba(0, 0, 0, 0.6);
            --window-bg: #f2f2f2;
            --text-color: #333;
        }

        * { box-sizing: border-box; margin: 0; padding: 0; }

        body, html {
            width: 100%;
            height: 100%;
            overflow: hidden;
            font-family: 'Ubuntu', sans-serif, Arial, sans-serif;
        }

        #desktop {
            width: 100vw;
            height: 100vh;
            background: linear-gradient(45deg, #300a24 0%, #772953 100%);
            position: relative;
            overflow: hidden;
        }

        /* Taskbar/Dock */
        #taskbar {
            position: absolute;
            bottom: 10px;
            left: 50%;
            transform: translateX(-50%);
            background: var(--ubuntu-panel);
            backdrop-filter: blur(10px);
            padding: 8px 20px;
            border-radius: 30px;
            display: flex;
            gap: 15px;
            align-items: center;
            z-index: 1000;
            border: 1px solid rgba(255,255,255,0.1);
        }

        #taskbar button {
            background: transparent;
            border: none;
            color: white;
            padding: 8px 15px;
            cursor: pointer;
            font-size: 14px;
            border-radius: 5px;
            transition: background 0.2s;
        }

        #taskbar button:hover {
            background: rgba(255, 255, 255, 0.2);
        }

        /* Window Styles */
        .window {
            position: absolute;
            width: 450px;
            height: 350px;
            min-width: 360px;
            min-height: 240px;
            background: var(--window-bg);
            border-radius: 8px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
            display: none;
            flex-direction: column;
            overflow: hidden;
            resize: both;
        }

        .window-header {
            background: #e0e0e0;
            padding: 8px 12px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            cursor: move;
            user-select: none;
        }

        .window-title {
            font-size: 13px;
            font-weight: bold;
            color: #444;
        }

        .win-close {
            background: #ff5f56;
            border: none;
            width: 12px;
            height: 12px;
            border-radius: 50%;
            cursor: pointer;
        }

        /* Files App Styles */
        .files-content {
            flex: 1;
            overflow-y: auto;
            padding: 10px;
            background: white;
        }

        #files-path-bar {
            display: flex;
            align-items: center;
            gap: 5px;
            padding: 5px 10px;
            background: #eee;
            font-size: 12px;
            border-bottom: 1px solid #ddd;
        }

        #files-up {
            cursor: pointer;
            padding: 2px 6px;
            background: #ddd;
            border-radius: 3px;
            font-weight: bold;
        }

        .fs-item {
            display: flex;
            align-items: center;
            padding: 5px;
            cursor: pointer;
            border-radius: 4px;
            font-size: 14px;
            user-select: none;
        }

        .fs-item:hover {
            background: #e8f0fe;
        }

        .fs-icon {
            margin-right: 8px;
            font-size: 16px;
        }

        /* Notepad Styles */
        #tabs {
            display: flex;
            background: #ddd;
            padding: 5px 5px 0 5px;
            gap: 2px;
        }

        .tab {
            padding: 6px 12px;
            background: #bbb;
            border-radius: 5px 5px 0 0;
            font-size: 12px;
            cursor: pointer;
            max-width: 120px;
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .tab.active {
            background: var(--window-bg);
        }

        #new-tab {
            padding: 5px;
            cursor: pointer;
            font-weight: bold;
            border: none;
            background: transparent;
        }

        #editor {
            flex: 1;
            width: 100%;
            border: none;
            padding: 10px;
            resize: none;
            font-family: monospace;
            font-size: 14px;
            outline: none;
        }

    </style>
</head>
<body>

<div id="desktop">
    <!-- Files Window -->
    <div id="files-window" class="window">
        <div class="window-header">
            <span class="window-title">Files</span>
            <button class="win-close"></button>
        </div>
        <div id="files-path-bar">
            <span id="files-up">..</span>
            <span id="files-path">/</span>
        </div>
        <div class="files-content" id="files-list">
            <!-- Items injected by JS -->
        </div>
    </div>

    <!-- Notepad Window -->
    <div id="notepad-window" class="window">
        <div class="window-header">
            <span class="window-title">Notepad</span>
            <button class="win-close"></button>
        </div>
        <div id="tabs">
            <!-- Tabs injected by JS -->
            <button id="new-tab">+</button>
        </div>
        <textarea id="editor" spellcheck="false"></textarea>
    </div>

    <!-- Taskbar -->
    <div id="taskbar">
        <button id="open-files">Files</button>
        <button id="open-notepad">Notepad</button>
    </div>
</div>

<script>
    /** FILESYSTEM LOGIC **/
    const fsData = {
        '/': { type: 'dir', children: ['bin', 'etc', 'home', 'usr', 'var'] },
        '/bin': { type: 'dir', children: ['ls', 'cp', 'mv', 'rm'] },
        '/etc': { type: 'dir', children: ['passwd', 'hosts', 'fstab'] },
        '/home': { type: 'dir', children: ['user'] },
        '/home/user': { type: 'dir', children: ['Documents', 'Downloads', 'Pictures', 'notes.txt'] },
        '/home/user/Documents': { type: 'dir', children: ['resume.pdf', 'budget.xlsx'] },
        '/home/user/Downloads': { type: 'dir', children: [] },
        '/home/user/Pictures': { type: 'dir', children: ['vacation.jpg'] },
        '/usr': { type: 'dir', children: ['bin', 'lib'] },
        '/var': { type: 'dir', children: ['log', 'tmp'] }
    };

    let currentPath = '/';

    const filesList = document.getElementById('files-list');
    const filesPathDisplay = document.getElementById('files-path');
    const filesUpBtn = document.getElementById('files-up');

    function renderFiles() {
        filesList.innerHTML = '';
        filesPathDisplay.innerText = currentPath;

        const dir = fsData[currentPath];
        if (!dir) return;

        // Add ".." button if not at root
        if (currentPath !== '/') {
            const upItem = document.createElement('div');
            upItem.className = 'fs-item';
            upItem.innerHTML = `<span class="fs-icon">⬆️</span><span>..</span>`;
            upItem.onclick = () => navigateUp();
            filesList.appendChild(upItem);
        }

        dir.children.forEach(name => {
            const itemPath = (currentPath === '/' ? '' : currentPath) + '/' + name;
            const isDir = fsData[itemPath] && fsData[itemPath].type === 'dir';

            const item = document.createElement('div');
            item.className = 'fs-item';
            item.innerHTML = `<span class="fs-icon">${isDir ? '📁' : '📄'}</span><span>${name}</span>`;

            item.ondblclick = () => {
                if (isDir) {
                    currentPath = itemPath;
                    renderFiles();
                }
            };
            filesList.appendChild(item);
        });
    }

    function navigateUp() {
        const parts = currentPath.split('/').filter(p => p !== '');
        parts.pop();
        currentPath = parts.length === 0 ? '/' : '/' + parts.join('/');
        renderFiles();
    }

    filesUpBtn.onclick = navigateUp;
    renderFiles();


    /** NOTEPAD LOGIC **/
    let tabs = []; // { id, title, content }
    let activeTabId = null;

    const tabContainer = document.getElementById('tabs');
    const editor = document.appElement = document.getElementById('editor');
    const newTabBtn = document.getElementById('new-tab');

    function initNotepad() {
        const saved = localStorage.getItem('notepad_data');
        if (saved) {
            const parsed = JSON.parse(saved);
            tabs = parsed.tabs || [];
            activeTabId = parsed.activeTabId;
        } else {
            // Default tab
            const firstId = Date.now().toString();
            tabs.push({ id: firstId, title: 'Untitled', content: '' });
            activeTabId = firstId;
        }
        renderTabs();
        switchTab(activeTabId);
    }

    function saveNotepad() {
        localStorage.setItem('notepad_data', JSON.stringify({ tabs, activeTabId }));
    }

    function renderTabs() {
        // Clear existing tabs (keep the + button)
        const buttons = tabContainer.querySelectorAll('.tab');
        buttons.forEach(b => b.remove());

        tabs.forEach(tab => {
            const el = document.createElement('div');
            el.className = `tab ${tab.id === activeTabId ? 'active' : ''}`;
            el.innerText = tab.title;
            el.onclick = () => switchTab(tab.id);
            tabContainer.insertBefore(el, newTabBtn);
        });
    }

    function switchTab(id) {
        activeTabId = id;
        const tab = tabs.find(t => t.id === id);
        if (tab) {
            editor.value = tab.content;
            renderTabs();
        }
    }

    newTabBtn.onclick = () => {
        const id = Date.now().toString();
        tabs.push({ id, title: 'Untitled', content: '' });
        activeTabId = id;
        renderTabs();
        switchTab(id);
        saveNotepad();
    };

    editor.oninput = (e) => {
        const tab = tabs.find(t => t.id === activeTabId);
        if (tab) {
            tab.content = e.target.value;
            // Update title if content exists
            if (tab.content.length > 0 && tab.title === 'Untitled') {
                tab.title = tab.content.substring(0, 10) + (tab.content.length > 10 ? '...' : '');
                renderTabs();
            }
            saveNotepad();
        }
    };

    initNotepad();


    /** WINDOW MANAGEMENT **/
    const winFiles = document.getElementById('files-window');
    const winNotepad = document.getElementById('appElement = document.getElementById('notepad-window');
    const btnFiles = document.getElementById('open-files');
    const btnNotepad = document.getElementById('open-notepad');

    btnFiles.onclick = () => {
        winFiles.style.display = 'flex';
        moveWindow(winFiles);
    };

    btnNotepad.onclick = () => {
        winNotepad.style.display = 'flex';
        moveWindow(winNotepad);
    };

    document.querySelectorAll('.win-close').forEach(btn => {
        btn.onclick = (e) => {
            e.target.closest('.window').style.display = 'none';
        };
    });

    // Simple Draggable Logic
    function moveWindow(win) {
        let pos1 = 0, pos2 = 0, pos3 = 0, pos4 = 0;
        const header = win.querySelector('.window-header');
        if (!header) return;

        header.onmousedown = dragMouseDown;

        function dragMouseDown(e) {
            e.preventDefault();
            pos3 = e.clientX;
            pos4 = e.clientY;
            document.onmouseup = closeDragElement;
            document.onmousemove = elementDrag;
            // Bring to front
            document.querySelectorAll('.window').forEach(w => w.style.zIndex = 10);
            win.style.zIndex = 100;
        }

        function elementDrag(e) {
            e.preventDefault();
            pos1 = pos3 - e.clientX;
            pos2 = pos4 - e.clientY;
            pos3 = e.clientX;
            pos4 = e.clientY;
            win.style.top = (win.offsetTop - pos2) + "px";
            win.style.left = (win.offsetLeft - pos1) + "px";
        }

        function closeDragElement() {
            document.onmouseup = null;
            document.onmousemove = null;
        }
    }

    // Initialize window positions
    moveWindow(winFiles);
    moveWindow(winNotepad);
    winFiles.style.top = '50px';
    winFiles.style.left = '50px';
    winNotepad.style.top = '120px';
    winNotepad.style.left = '520px';

</script>
</body>
</html>
